/// <summary>
/// Extension of the <c>SalesAgreementGenerateReleaseOrder</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(SalesAgreementGenerateReleaseOrder))]
final class SalesAgreementGenerateReleaseOrderETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromAgreementLineQuantityCommitment</c> method.
/// </summary>
/// <param name="_salesCreateReleaseOrderLineTmp">SalesCreateReleaseOrderLineTmp.</param>
/// <param name="_agreementLineQuantityCommitment">AgreementLineQuantityCommitment.</param>
public void initFromAgreementLineQuantityCommitment(SalesCreateReleaseOrderLineTmp _salesCreateReleaseOrderLineTmp, AgreementLineQuantityCommitment _agreementLineQuantityCommitment)
{
    next initFromAgreementLineQuantityCommitment(_salesCreateReleaseOrderLineTmp,  _agreementLineQuantityCommitment);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        AgreementHeader     agreementHeader = _agreementLineQuantityCommitment.agreementHeader();
        InventDim           inventDim;
        InventSerial        inventSerial;

        // Inicializamos el valor del contrato cuando se trata de Cupos
        if (agreementHeader.ETGSPAINPurchHasAgreementQuotas)
        {
            inventSerial = InventSerial::findOrCreate(_agreementLineQuantityCommitment.ETGSPAINLineCode, _agreementLineQuantityCommitment.ItemId);

            inventDim                                   = _salesCreateReleaseOrderLineTmp.inventDim();
            inventDim.inventSerialId                    = inventSerial.InventSerialId;
            inventDim                                   = InventDim::findOrCreate(inventDim);
            _salesCreateReleaseOrderLineTmp.InventDimId = inventDim.inventDimId;
        }
    }
}
